/// <summary>
/// This class is an extension of form CustParameters and dataSource SalesParameters
/// </summary>
[ExtensionOf(formDataSourceStr(CustParameters, SalesParameters))]
internal final class ETGCustParameters_SalesParameters_Extension
{
}

Method.Source:
/// <summary>
/// Contains the logic for the visibility of form control when CylinderTracking feature is enabled
/// </summary>
/// <returns></returns>
public int active()
{
    int ret =  next active();

    this.object(fieldNum(SalesParameters, ETGMainAccountRecId)).visible(SalesParameters::find().ETGEnableCylinderTracking == NoYes::Yes);

    return ret;
}
